import anthropic, json, jsonschema

# Tool definition including its JSON Schema
SEARCH_TOOL = {
    "name": "search",
    "description": "Search for information on a topic.",
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {"type": "string", "minLength": 1},
            "max_results": {"type": "integer", "minimum": 1, "maximum": 20},
        },
        "required": ["query"],
        "additionalProperties": False,
    },
}

TOOLS = [SEARCH_TOOL]

def validate_tool_call(tool_name: str, tool_args: dict) -> tuple[bool, str | None]:
    """
    Validate a tool call against its declared schema.
    Returns (valid, error_message).
    """
    schema_map = {t["name"]: t["input_schema"] for t in TOOLS}
    if tool_name not in schema_map:
        return False, f"Unknown tool: '{tool_name}'"
    try:
        jsonschema.validate(instance=tool_args, schema=schema_map[tool_name])
        return True, None
    except jsonschema.ValidationError as e:
        return False, e.message

@dataclasses.dataclass
class ToolCallRecord:
    tool_name: str
    args: dict
    schema_valid: bool
    error: str | None = None

import dataclasses

def run_and_validate(user_question: str) -> list[ToolCallRecord]:
    client = anthropic.Anthropic()
    messages = [{"role": "user", "content": user_question}]
    records: list[ToolCallRecord] = []

    for _ in range(5):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=256,
            tools=TOOLS,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            break

        if resp.stop_reason == "tool_use":
            tool_results = []
            for block in resp.content:
                if block.type == "tool_use":
                    valid, err = validate_tool_call(block.name, block.input)
                    records.append(ToolCallRecord(
                        tool_name=block.name,
                        args=block.input,
                        schema_valid=valid,
                        error=err,
                    ))
                    result = "Sample search result." if valid else f"Rejected: {err}"
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages += [
                {"role": "assistant", "content": resp.content},
                {"role": "user", "content": tool_results},
            ]

    return records

records = run_and_validate("Find information about neural networks.")
for r in records:
    status = "VALID" if r.schema_valid else f"INVALID: {r.error}"
    print(f"  {r.tool_name}({json.dumps(r.args)}) → {status}")

import anthropic, dataclasses, json

@dataclasses.dataclass
class SemanticCheckCase:
    task: str
    expected_tool: str
    argument_checks: dict   # {arg_name: callable that returns bool}

def run_semantic_check(case: SemanticCheckCase) -> dict:
    client = anthropic.Anthropic()
    messages = [{"role": "user", "content": case.task}]

    tools = [
        {
            "name": "search",
            "description": "Search for information.",
            "input_schema": {
                "type": "object",
                "properties": {"query": {"type": "string"}},
                "required": ["query"],
            },
        },
        {
            "name": "get_price",
            "description": "Look up the price of a stock symbol.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "symbol": {"type": "string", "description": "Uppercase ticker symbol, e.g. AAPL"},
                    "currency": {"type": "string", "enum": ["USD", "EUR", "GBP"]},
                },
                "required": ["symbol", "currency"],
            },
        },
    ]

    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        tools=tools,
        messages=messages,
    )

    results = {"tool_selected_correctly": False, "argument_checks": {}, "raw_calls": []}
    for block in resp.content:
        if block.type == "tool_use":
            results["raw_calls"].append({"name": block.name, "args": block.input})
            if block.name == case.expected_tool:
                results["tool_selected_correctly"] = True
                for arg, check_fn in case.argument_checks.items():
                    val = block.input.get(arg)
                    results["argument_checks"][arg] = {
                        "value": val,
                        "passed": check_fn(val) if val is not None else False,
                    }

    return results

# Example: verify the agent uses the correct ticker and uppercase currency
case = SemanticCheckCase(
    task="What is the current price of Apple stock in US dollars?",
    expected_tool="get_price",
    argument_checks={
        "symbol": lambda v: v.upper() == "AAPL",
        "currency": lambda v: v == "USD",
    },
)

result = run_semantic_check(case)
print(json.dumps(result, indent=2))
